settings.custom_liquid:
{% assign primary_category = product.metafields.category.primary %}
{% if primary_category != blank %}
  {% assign category_collection = collections[primary_category] %}
  <section class="category-products" style="padding: 40px 0;">
      <div class="category-products__header">
        <a class="uppercase button" href="{{ category_collection.url }}">
          {{ category_collection.handle | capitalize }}
        </a>
      </div>

      <div style="display: flex
;
    flex-direction: row;
    flex-wrap: wrap; margin-top: 20px; gap: 20px;">
        {% if category_collection.products.size > 0 %}
          {% assign product_count = 0 %}
          {% for category_product in category_collection.products limit: 48 %}
            {% if category_product.id == product.id %}
              {% continue %}
            {% endif %}

            {% if product_count < 48 %}
              <div class="resource-list__item ">
                <a class=" uppercase" href="{{ category_product.url }}">
                  {{ category_product.title }}
                </a>
              </div>
              {% assign product_count = product_count | plus: 1 %}
            {% endif %}
          {% endfor %}
        {% else %}
          <p class="paragraph">No products found in this category.</p>
        {% endif %}
      </div>
  </section>
{% endif %}
